const e=JSON.parse(`[{"photos":["images/projects/2022/3e_oeil_prope/577A6649.jpg","images/projects/2022/3e_oeil_prope/Jetzer-Noa-3eme-oeil9.jpg","images/projects/2022/3e_oeil_prope/book3eoeil3.jpg","images/projects/2022/3e_oeil_prope/book3eoeil2.jpg","images/projects/2022/3e_oeil_prope/577A6034-2.jpg","images/projects/2022/3e_oeil_prope/Jetzer-Noa-3eme-oeil5.jpg","images/projects/2022/3e_oeil_prope/Jetzer-Noa-3eme-oeil3.jpg","images/projects/2022/3e_oeil_prope/Jetzer-Noa-3eme-oeil1.jpg","images/projects/2022/3e_oeil_prope/577A6652.jpg"],"title":"Third Eye","slug":"third-eye","category":"Photography","date":"2022","referencement":"Foundation year project at ECAL, with Daniela Droz and Tonatiuh Ambrosetti.","description":"For as long as I can remember, I have spent Christmas with my family—yet I remain a stranger among them. I know them only through the stories my parents tell and the faded images preserved in family archives. Beyond the bond of blood, there seems to be nothing that truly connects us.<p>I have chosen to immerse myself in these archives, tracing the fragments of their lives and memories in search of moments, gestures, or details that might bridge the distance between us.","link":""},{"photos":["images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/577A7410 copie.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/577A6993-Edit copie.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/Plan de travail 1.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/577A7458 copie 2.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/577A7539 copie 2.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/577A7577-Edit copie 2.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/577A7593-Edit copie 2.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/arbre-577A7454 copie.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/branches-577A7405 copie.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/Plan de travail 2.jpg","images/projects/2023/1cvdg_1sem-C.Leutenegger-photo/valency-96.jpg"],"title":"Shaped Nature","slug":"shaped-nature","category":"Photography","date":"2023","referencement":"First-year Bachelor project at ECAL, with Catherine Leutenegger.","description":"A park is nature, but constructed. It is both a place of calm and of movement. A space where I walk, think, and notice. My photographs capture its dynamic side: spontaneous moments, traces of human presence, and the subtle structures that have merged with the landscape. Here, design and growth meet in contrast, tension, and harmony.","link":""},{"photos":["images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/thumbnail_l-guyot-1cvdg.jpg","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/577A7191.jpg","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/Jetzer-Noa_Teaser.mp4","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/577A7199.jpg","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/Jetzer-Noa_Sequence.mp4","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/RPReplay_Final1704644766.mp4","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/RPReplay_Final1704644787.mp4","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/RPReplay_Final1704644807.mp4","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/RPReplay_Final1704644826.mp4","images/projects/2023/1cvdg-1sem-L.Guyot-sequence2d/teste-camera10001-0096.mp4"],"title":"Dans la Tête de Jules","slug":"dans-la-tete-de-jules","category":"Animation","date":"2023","referencement":"First-year Bachelor project at ECAL, with Léonard Guyot, featuring Jules Monod.","description":"A video project delving into the inner world of artist Jules Monod. Using 3D scanning and modeling, I set out to recreate a dream he once described to me; a dream steeped in chaos and confusion. We wander through his art as though navigating the very architecture of his mind.","link":""},{"photos":["images/projects/2023/concours_entree_bachelor/IMG_3854.jpg","images/projects/2023/concours_entree_bachelor/gem3.jpg","images/projects/2023/concours_entree_bachelor/IMG_3828.jpg","images/projects/2023/concours_entree_bachelor/IMG_3829.jpg","images/projects/2023/concours_entree_bachelor/IMG_3830.jpg","images/projects/2023/concours_entree_bachelor/IMG_3851.jpg","images/projects/2023/concours_entree_bachelor/IMG_3852.jpg","images/projects/2023/concours_entree_bachelor/IMG_3853.jpg","images/projects/2023/concours_entree_bachelor/IMG_3855.jpg","images/projects/2023/concours_entree_bachelor/IMG_3856.jpg","images/projects/2023/concours_entree_bachelor/IMG_3857.jpg","images/projects/2023/concours_entree_bachelor/IMG_3858.jpg","images/projects/2023/concours_entree_bachelor/IMG_3859.jpg","images/projects/2023/concours_entree_bachelor/IMG_3860.jpg","images/projects/2023/concours_entree_bachelor/IMG_3862.jpg","images/projects/2023/concours_entree_bachelor/IMG_3863.jpg"],"title":"Bob","slug":"bob","category":"Fanzine","date":"2023","referencement":"Proposed project for the ECAL Bachelor entrance competition.","description":"I chose to explore the theme of deepfakes, creating a universe around a generic character, who, in the end, does not exist. The project raises questions about identity and representation in the digital age.","link":""},{"photos":["images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper34.jpg","images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper28.jpg","images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper29.jpg","images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper30.jpg","images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper31-2.jpg","images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper32.jpg","images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper33.jpg","images/projects/2023/Guy_Meldem-S-1-2023-1CVDG/copper35.jpg"],"title":"A guide to making good Italian coffee if you are a dog waiter","slug":"a-guide-to-making-good-italian-coffee-if-you-are-a-dog-waiter","category":"Fanzine","date":"2023","referencement":"First-year Bachelor project at ECAL, with Guy Meldem, featuring Léo the Dog.","description":"Through this small illustrated booklet, I chose to feature our late dog as the main character, guiding us step by step on how to make a perfect cup of coffee. The booklet was created using a two-color process, with a green layer printed by laser and a pink layer overprinted in risograph.","link":""},{"photos":["images/projects/2023/Robert_Huber-S-2-2023-1CVDG/Repros-adeline60.jpg","images/projects/2023/Robert_Huber-S-2-2023-1CVDG/typo06.jpg","images/projects/2023/Robert_Huber-S-2-2023-1CVDG/video-cahier-recherche.mp4","images/projects/2023/Robert_Huber-S-2-2023-1CVDG/Repros-adeline61.jpg"],"title":"King, Typography","slug":"king-typography","category":"Typography","date":"2023","referencement":"First-year Bachelor project at ECAL, with Robert Huber.","description":"Continuation of the hand-drawn lowercase project, creating a medium rounded weight.","link":""},{"photos":["images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/IMG_5498.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper04.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper05.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper06.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper07.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper08.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper18.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper20.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper21.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/copper26.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/noa_3.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/terre-enfer-ciel-extrait.jpg","images/projects/2023/S-1-2023-1CVDG-Adeline_Mollard/vectorisations-12.jpg"],"title":"Play with the children of Prélaz","slug":"play-with-the-children-of-prelaz","category":"Visual identity","date":"2023","referencement":"First-year Bachelor project at ECAL, with Adeline Mollard.","description":"We were tasked with creating a visual identity based on our neighborhood. In my case, Prélaz. I chose to work with the primary school located across from where I lived at the time. I collected and then deconstructed the playground games, with the goal of designing a new, modular game that could be adapted in countless ways. The pages of the edition can be detached, allowing the game to be rebuilt on the ground using its various components. Interspersed with sticker pages, the publication is designed to be playful and interactive.","link":""},{"photos":["images/projects/2023/violene_pont-2023/IMG_4297.jpg","images/projects/2023/violene_pont-2023/video-flyers-insta.MP4","images/projects/2023/violene_pont-2023/IMG_4303.jpg","images/projects/2023/violene_pont-2023/IMG_4302.jpg","images/projects/2023/violene_pont-2023/IMG_4301.jpg","images/projects/2023/violene_pont-2023/IMG_4300.jpg","images/projects/2023/violene_pont-2023/IMG_2951.jpg"],"title":"La Brocante","slug":"la-brocante","category":"Flyers","date":"2023","referencement":"Foundation year project at ECAL, with Violène Pont.","description":"A series of ten flyers promoting various second-hand events across the Canton of Vaud. I photographed vintage toys and handcrafted the paper, then printed each flyer at home using a small inkjet printer.","link":""},{"photos":["images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline53.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/IMG_9702.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Jetzer-Noa-Video-Mollard.mp4","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/posternoa.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline02.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline03.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline06.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline11.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline16.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline26.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline30.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline34.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline45.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/Repros-adeline58.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/RPReplay_Final1713274037.mov","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/thumbnail-adeline-1cvdg-s2.jpg","images/projects/2024/Adeline_Mollard-S-2-2024-1CVDG/WhatsApp Image 2025-08-09 at 15.13.42.jpeg"],"title":"72 Flyers","slug":"72-flyers","category":"Visual identity","date":"2024","referencement":"First-year Bachelor project at ECAL, with Adeline Mollard.","description":"This catalog is a personal archive documenting my interest in graphic design from ages 20 to 24, coinciding with my entry into ÉCAL. It brings together 72 flyers, selected from over 200 collected between 2020 and 2024. My objective was to deconstruct the traditional flyer format to identify its core visual and material characteristics, such as size, color palette, typography, imagery, and composition. The collection is organized into three distinct categories: Standard flyers created by professional graphic designers. High-quality flyers, distinguished by superior paper, printing techniques, and design. Vernacular flyers, handmade by amateurs or non-designers, often with unique and spontaneous visual qualities. Through this selection, I explore how different approaches to design—professional, refined, or improvised—shape the visual identity and communicative power of a flyer","link":""},{"photos":["images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/double-cover.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/p-6.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/p-2.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/jaquette.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/p-5.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/p-7.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/Affiche-Verso-Insta.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/noamockup.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/p-3.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/p-4.jpg","images/projects/2024/Diego_Bontognalli-S-1-2024-2CVDG/Video-Jetzer-Noa.mp4"],"title":"The Greatest Show on Earth!(?), Freak Shows Through Headlines","slug":"the-greatest-show-on-earth-freak-shows-through-headlines","category":"Book design","date":"2024","referencement":"First-year Bachelor project at ECAL, with Diego Bontognalli.","description":"The Greatest Show on Earth!(?), Freak Shows Through Headlines is an editorial project built from American newspaper archives (1865–2005) exploring how so-called “freak” artists, often marginalized and exhibited as curiosities, were represented in popular press for over a century. Through a collage of articles, photographs, dispatches, and fragmented stories, the project examines the thin line between entertainment and dehumanization. It contrasts the sensationalized, mocking, or fascinated public image shaped by the media with rare glimpses of personal lives—love, family, work. Newspapers are both source and material: by reframing and assembling them, the project offers a critical reading of these narratives, revealing moments of tenderness alongside systemic exploitation of bodies for spectacle. Ultimately, the work reflects on how media constructs stories from difference, raising questions that remain urgent today: Who is granted a full, nuanced, human narrative? Whose voices are amplified, and whose are silenced behind the spectacle? By recontextualizing these archives, the project uses graphic editing as a tool for critique, memory, and reclamation.","link":""},{"photos":["images/projects/2024/elodie_anglade-S-2-2024-1CVDG/scene1_0100.jpg","images/projects/2024/elodie_anglade-S-2-2024-1CVDG/3scenes-redshift.mp4","images/projects/2024/elodie_anglade-S-2-2024-1CVDG/Atest.jpg","images/projects/2024/elodie_anglade-S-2-2024-1CVDG/IMG_0339.jpg","images/projects/2024/elodie_anglade-S-2-2024-1CVDG/3scenes.mp4","images/projects/2024/elodie_anglade-S-2-2024-1CVDG/IMG-20240304-WA0062.jpg","images/projects/2024/elodie_anglade-S-2-2024-1CVDG/scene1_0116.jpg"],"title":"Misery of the Hearts","slug":"misery-of-the-hearts","category":"Animation","date":"2024","referencement":"First-year Bachelor project at ECAL, with Elodie Anglade.","description":"This project offers an animated reinterpretation of the visual work of Swiss artist Marianne Eigenheer, whose artistic language navigates between meditative stillness and expressive tension. Composed of three scenes designed and modeled in Cinema 4D, the work aims to translate the evocative power of her practice into a digital, moving medium. Presented as a triptych, these sequences extend the contemplative atmosphere and subtle melancholy of the original piece, while opening new visual possibilities through the interplay of light, texture, and rhythm.","link":""},{"photos":["images/projects/2024/casa-nostra-2024/IMG_1970.jpg","images/projects/2024/casa-nostra-2024/IMG-20240629-WA0043.jpg","images/projects/2024/casa-nostra-2024/Free_Clipboard_Mockup_4.jpg","images/projects/2024/casa-nostra-2024/Free_Clipboard_Mockup_5.jpg","images/projects/2024/casa-nostra-2024/Free_Clipboard_Mockup_2.jpg"],"title":"Menu for Casa Nostra","slug":"menu-for-casa-nostra","category":"Menu design","date":"2024","referencement":"Comission for the Casa Nostra restaurant in Martigny.","description":"After five years working in the Italian restaurant Casa Nostra, I have grown deeply attached to its warm family story and traditional atmosphere. To refresh the menu, I used hand-drawn illustrations and custom typography, blending tradition with a contemporary feel, blending with the décor and the restaurant’s elaborate pasta creations.","link":""},{"photos":["images/projects/2024/helas-studio-2024/FINAL.jpg","images/projects/2024/helas-studio-2024/3d-video.mp4","images/projects/2024/helas-studio-2024/magritte-le-rideau.jpg","images/projects/2024/helas-studio-2024/maquette20001.jpg","images/projects/2024/helas-studio-2024/MV5BMGNhMzkxMDEtMjJiZi00NzA3LWFjMTEtMDkyNGE5N2NkMjE3XkEyXkFqcGdeQXVyOTc5MDI5NjE@._V1_FMjpg_UX2000_.jpg","images/projects/2024/helas-studio-2024/windows-xp-hd.jpg","images/projects/2024/helas-studio-2024/19f400e40c085733a043d331468633d7.jpg"],"title":"\\"We are going to fight fire with marshmallows\\"","slug":"we-are-going-to-fight-fire-with-marshmallows","category":"Poster","date":"2024","referencement":"First-year Bachelor workshop at ECAL, with Helas Studio.","description":"This poster is a reinterpretation of one of my favorite films, Toys by Barry Levinson, starring Robin Williams. My goal was to convey both the chaos and the sense of childhood innocence present in the story, while staying true to its plot without revealing any spoilers. Designed as a toy box, the poster’s interior scene was created in 3D using Blender.","link":""},{"photos":["images/projects/2024/theatre-parhelia-2024/Thumbnail-pharelia.jpg","images/projects/2024/theatre-parhelia-2024/Affiches-theatre.jpg","images/projects/2024/theatre-parhelia-2024/IMG_3219.jpg","images/projects/2024/theatre-parhelia-2024/Double_Vertical_5.jpg"],"title":"Femmes de Troie","slug":"femmes-de-troie","category":"Poster and flyer","date":"2024","referencement":"Comission for the Parhélia theatre troupe, Flavie Tapparel.","description":"Featuring Elisa Feraud’s art, I designed a poster for Femmes de Troie, a play by the Parhélia theatre troupe.","link":""},{"photos":["images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/Anouk 25-092.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/Anouk 25-086.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/hands_showing_2.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/Anouk 25-087.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/IMG_2342.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/hands_showing.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/Anouk 25-089.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/IMG_2346.jpg","images/projects/2024/Transversal-2CVDG-S-1-Polli_Schneider-2024/Anouk 25-090.jpg"],"title":"FindFoot, We <3 Feet","slug":"findfoot-we-love-feet","category":"Book design","date":"2024","referencement":"Second-year Bachelor project at ECAL, with Anouk Schneider and Nicolas Polli. In collaboration with Colas Ravey.","description":"The graphic choices for this editorial project were inspired by our primary reference, FeetFinder. The color palette highlights its signature purple, while selected pages are printed on pink paper to feature the descriptions from our posts on the site. These bright inserts also nod to the “pink pages” of adult phone services. The small format and minimalist cover allow for discreet browsing, respecting the potential sensitivity of the content. The book’s structure is simple: it begins with a glossary of the site’s tags, each linked to one or more corresponding images, ensuring that even very specific interests are addressed. Overall, the project offers a playful yet thoughtful exploration of its subject matter.","link":""},{"photos":["images/projects/2024/workshop-2024/thumbnail-workshop.jpg","images/projects/2024/workshop-2024/ALLUMEZ 2.MP4","images/projects/2024/workshop-2024/COMPRESSEZ.MP4","images/projects/2024/workshop-2024/VOYAGEZ.MP4","images/projects/2024/workshop-2024/IMG_2324.jpg","images/projects/2024/workshop-2024/scan08.jpg","images/projects/2024/workshop-2024/IMG_2290.mov","images/projects/2024/workshop-2024/test-anim-1.mp4","images/projects/2024/workshop-2024/test-anim-2.mp4","images/projects/2024/workshop-2024/video-stop-motion.mp4"],"title":"Digital Cleanup Week","slug":"digital-cleanup-week","category":"Animated posters","date":"2024","referencement":"First-year Bachelor workshop at ECAL, with Angelo Benedetto and Vincent Jacquier. In collaboration with Amélie Mathey.","description":"Proposal for a series of three animated posters and one main poster for Digital Cleanup Week, organized by HES-SO. This collaborative project involved creating hand-drawn stop-motion animations, giving a playful and engaging character to the event’s visual identity.","link":""},{"photos":["images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/repro_ba2s2_251_traitee.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/repro_ba2s2_255_traitee.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/Capture ecran 2025-08-09 a 17.25.56.jpg","images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/repro_ba2s2_252_traitee.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/repro_ba2s2_253_traitee.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/Plan de travail 3.jpg","images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/repro_ba2s2_254_traitee.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-2CVDG-S-2-2025/Capture ecran 2025-08-09 a 17.26.22.jpg"],"title":"Arancino","slug":"arancino","category":"Typography","date":"2025","referencement":"Second-year Bachelor project at ECAL, with Aurèle Sack.","description":"Arancino is a fun and rounded typeface developed in two main stages. I began by sketching each letter by hand, experimenting with curves and shapes to give the font its playful character. After refining the sketches, I moved on to Glyphs, where I carefully drew both the uppercase and lowercase characters. The final result is a lively, approachable font that combines precision with a handcrafted feel, perfect for projects that want to convey friendliness, warmth, and personality.","link":""},{"photos":["images/projects/2025/balmer_hahlen-2025/IMG_3580.jpg","images/projects/2025/balmer_hahlen-2025/Affiche-A0-V3-couce-rose.jpg","images/projects/2025/balmer_hahlen-2025/IMG_3573.mp4","images/projects/2025/balmer_hahlen-2025/IMG_3574.jpg","images/projects/2025/balmer_hahlen-2025/IMG_3579.jpg","images/projects/2025/balmer_hahlen-2025/IMG_3596.jpg"],"title":"Cartoon Network used to rock but not anymore and that makes me sad","slug":"cartoon-network-used-to-rock-but-not-anymore-and-that-makes-me-sad","category":"Poster","date":"2025","referencement":"Second-year Bachelor workshop at ECAL, with studio Balmer Hählen.","description":"This project consisted of creating a poster that captures the nostalgic feeling of a ‘Madeleine de Proust’ moment. I drew inspiration from my childhood memories of watching Cartoon Network, an experience I no longer have, which brings a bittersweet awareness of growing up. The poster was created using a two-color process: the first layer was printed with inkjet, and the second was screen-printed.","link":"https://www.instagram.com/p/DHI-IEbs5I-/"},{"photos":["images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux09.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/IMG_4614.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux03.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux04.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux05.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux06.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux07.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux08.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux12.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux13.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux20.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/oiseaux23.jpg","images/projects/2025/Nicole_Udry-S-2-2CVDG-2025/PHOTO-2025-03-12-21-07-42 4.jpg"],"title":"Et si l'on pouvait comprendre les Oiseaux","slug":"et-si-lon-pouvait-comprendre-les-oiseaux","category":"Design in context","date":"2025","referencement":"Second-year Bachelor workshop at ECAL, with Nicole Urdy.","description":"This project was created for the Maison de l’Île aux Oiseaux in Préverenges. It explores translating sensations into visual form, capturing sound, silence, and movement through images and blind embossing. A dialogue unfolds between person, bird, and the house itself, creating a cyclical rhythm. The book becomes a space of contemplation, where image, material, and memory intertwine to extend the original experience.","link":""},{"photos":["images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-009_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-012_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-015_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-016_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-017_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/presse-tshirt.mp4","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-018_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-019_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-020_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-021_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-022_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-023_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-024_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-025_1.jpg","images/projects/2025/S-2-Cirimele_Schneider-2025/Anouk 2025 S2-026_1.jpg"],"title":"CHEER Magazine","slug":"cheer-magazine","category":"Magazine design","date":"2025","referencement":"Second-year Bachelor project at ECAL, with Anouk Schneider and Emmanuel Crivelli. In collaboration with Colas Ravey.","description":"CHeer is a magazine that celebrates and highlights Swiss queer youth. Through personal stories, portraits, and cultural explorations, we give a voice to those who are shaping queer identities today. CHeer is a space for visibility, affirmation, and celebration, where experiences intersect and are shared. Because queer youth deserve to be heard, because stories are diverse, complex, and luminous, this magazine exists to document, inspire, and bring people together.","link":""},{"photos":["images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/noaj_td-01.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/thumbnailnoaj_td-08.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/noaj_td-02.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/noaj_td-09.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/noaj_td-03.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/noaj_td-04.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/noaj_td-05.jpg__0x1280_q85_subsampling-2.jpg","images/projects/2025/Aurele_Sack-3CVDG-S-1-2025/noaj_td-07.jpg__0x1280_q85_subsampling-2.jpg"],"title":"Dys Typeface","slug":"dys-typeface","category":"Typography","date":"2025","referencement":"Third-year Bachelor project at ECAL, with Aurèle Sack.","description":"Developed as an exploration of accessible typography, this typeface aims to facilitate reading for people with dyslexia. A deliberate concentration of visual weight in the lower part of each character reinforces orientation and helps differentiate similar letterforms. Several letters also feature alternative designs that break conventional symmetry, reducing potential confusion between mirrored or closely related characters. The project investigates how typographic form can actively support readability without compromising expressive design.","link":""},{"photos":["images/projects/2025/jon_hares_3CVDGS1/Thumbnailcover.jpg","images/projects/2025/jon_hares_3CVDGS1/inside_2.jpg","images/projects/2025/jon_hares_3CVDGS1/hand_2.jpg","images/projects/2025/jon_hares_3CVDGS1/inside_1.jpg","images/projects/2025/jon_hares_3CVDGS1/close-up_1.jpg","images/projects/2025/jon_hares_3CVDGS1/IMG_5563.jpg","images/projects/2025/jon_hares_3CVDGS1/inside_3.jpg","images/projects/2025/jon_hares_3CVDGS1/hand_3.jpg","images/projects/2025/jon_hares_3CVDGS1/inside_4.jpg","images/projects/2025/jon_hares_3CVDGS1/close-up_2.jpg","images/projects/2025/jon_hares_3CVDGS1/inside_5.jpg","images/projects/2025/jon_hares_3CVDGS1/IMG_5573.jpg","images/projects/2025/jon_hares_3CVDGS1/inside_6.jpg","images/projects/2025/jon_hares_3CVDGS1/inside_7.jpg"],"title":"Making Architecture Beautiful Again","slug":"making-architecture-beautiful-again","category":"Editorial design","date":"2025","referencement":"Third-year Bachelor project at ECAL, with Jonathan Hares.","description":"The book examines a decree signed during Donald Trump’s presidency that proposed classical architecture as the mandatory style for new U.S. federal buildings. By sequencing the decree’s language alongside critical texts and analyses, the project explores how ideas of beauty, heritage, and national identity become political tools. Printed with gold silkscreen overlays, the book critiques the use of aesthetics as a vehicle for ideological control.","link":""},{"photos":["images/projects/2025/ANTIGEL_Adeline_mollard_2cvDG_S1/ThumbnailAntigelposter_1_creditsMarvinMerkel.jpg","images/projects/2025/ANTIGEL_Adeline_mollard_2cvDG_S1/577A8734.jpg","images/projects/2025/ANTIGEL_Adeline_mollard_2cvDG_S1/Antigelposter_7_creditsmarvinMerkel.jpg","images/projects/2025/ANTIGEL_Adeline_mollard_2cvDG_S1/577A8758.jpg","images/projects/2025/ANTIGEL_Adeline_mollard_2cvDG_S1/mockup_video.mp4"],"title":"Variety of Connecions","slug":"variety-of-connecions","category":"Visual identity","date":"2025","referencement":"Second-year Bachelor project at ECAL, with Adeline Mollard.","description":"Created as part of a visual identity course made with Gabriel Polgar, this project was selected as the official visual identity for the 2026 edition of the Antigel Festival, in Geneva. Inspired by the structure of a modular synthesizer, the identity translates the festival’s experimental spirit into a dynamic grid system based on the geographical locations of its venues. Animated, flexible, and constantly evolving, the visual language reflects Antigel’s ability to transform spaces, connect communities, and redefine cultural boundaries.","link":"https://www.instagram.com/p/DQG6je2jMQf/"}]`),o={projects:e};export{o as d};
